const STORAGE_KEY = 'fundflow_tracked_items';
const IGNORED_KEY = 'fundflow_ignored_items';
const EVENT_KEY = 'fundflow_tracking_update';
const INDICES_KEY = 'fundflow_tracked_indices';

const DEFAULT_ITEMS: TrackedItem[] = [
  { id: 'RELIANCE', name: 'Reliance Industries Ltd', symbol: 'RELIANCE', type: 'STOCK' },
  { id: 'HDFCBANK', name: 'HDFC Bank Ltd', symbol: 'HDFCBANK', type: 'STOCK' },
  { id: 'ZOMATO', name: 'Zomato Ltd', symbol: 'ZOMATO', type: 'STOCK' },
  { id: 'PAYTM', name: 'One97 Communications Ltd', symbol: 'PAYTM', type: 'STOCK' },
  { id: 'RVNL', name: 'Rail Vikas Nigam Ltd', symbol: 'RVNL', type: 'STOCK' },
  { id: 'IRFC', name: 'Indian Railway Finance Corp', symbol: 'IRFC', type: 'STOCK' },
  { id: 'JIOFIN', name: 'Jio Financial Services', symbol: 'JIOFIN', type: 'STOCK' },
  { id: 'VBL', name: 'Varun Beverages Ltd', symbol: 'VBL', type: 'STOCK' },
  { id: 'HAL', name: 'Hindustan Aeronautics Ltd', symbol: 'HAL', type: 'STOCK' },
  { id: 'BEL', name: 'Bharat Electronics Ltd', symbol: 'BEL', type: 'STOCK' },
  { id: 'TRENT', name: 'Trent Ltd', symbol: 'TRENT', type: 'STOCK' },
  { id: 'MAZDOCK', name: 'Mazagon Dock Shipbuilders', symbol: 'MAZDOCK', type: 'STOCK' },
];

const DEFAULT_IGNORED_ITEMS: string[] = [
  "ADANIENSOL", "ADANIGREEN", "ADANITRANS", "POLICYBZR"
];

const DEFAULT_INDICES = ["NIFTY NEXT 50","NIFTY 50", "NIFTY BANK", "NIFTY IT"];

export const getTrackedItems = (): TrackedItem[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      return JSON.parse(stored);
    } else {
      // Initialize with defaults if empty
      localStorage.setItem(STORAGE_KEY, JSON.stringify(DEFAULT_ITEMS));
      return DEFAULT_ITEMS;
    }
  } catch (e) {
    console.error("Error parsing tracked items", e);
    return [];
  }
};

export const addTrackedItem = (item: TrackedItem) => {
  const items = getTrackedItems();

  // Check limit for Stocks (Max 50)
  if (item.type === 'STOCK') {
      const stockCount = items.filter(i => i.type === 'STOCK').length;
      if (stockCount >= 50) {
          alert("Watchlist limit reached. You can track a maximum of 50 stocks.");
          return;
      }
  }

  // Prevent duplicates
  if (!items.find(i => i.id === item.id && i.type === item.type)) {
    const newItems = [...items, item];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
    // Dispatch event to notify listeners (like Dashboard) to auto-refresh
    window.dispatchEvent(new Event(EVENT_KEY));
  }
};

export const removeTrackedItem = (id: string, type: EntityType) => {
  const items = getTrackedItems();
  const newItems = items.filter(i => !(i.id === id && i.type === type));
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
  // Dispatch event to notify listeners
  window.dispatchEvent(new Event(EVENT_KEY));
};

export const isTracked = (id: string, type: EntityType): boolean => {
  const items = getTrackedItems();
  return !!items.find(i => i.id === id && i.type === type);
};

// --- Ignore List Logic ---

export const getIgnoredItems = (): string[] => {
  try {
    const stored = localStorage.getItem(IGNORED_KEY);
    if (stored) {
      return JSON.parse(stored);
    } else {
      localStorage.setItem(IGNORED_KEY, JSON.stringify(DEFAULT_IGNORED_ITEMS));
      return DEFAULT_IGNORED_ITEMS;
    }
  } catch (e) {
    console.error("Error parsing ignored items", e);
    return DEFAULT_IGNORED_ITEMS;
  }
};

export const addIgnoredItem = (symbol: string) => {
  const items = getIgnoredItems();
  if (!items.includes(symbol)) {
    const newItems = [...items, symbol];
    localStorage.setItem(IGNORED_KEY, JSON.stringify(newItems));
    window.dispatchEvent(new Event(EVENT_KEY));
  }
};

export const removeIgnoredItem = (symbol: string) => {
  const items = getIgnoredItems();
  const newItems = items.filter(i => i !== symbol);
  localStorage.setItem(IGNORED_KEY, JSON.stringify(newItems));
  window.dispatchEvent(new Event(EVENT_KEY));
};

export const isIgnored = (symbol: string): boolean => {
  const items = getIgnoredItems();
  return items.includes(symbol);
};

// --- Index Tracking Logic ---

export const getTrackedIndices = (): string[] => {
  try {
    const stored = localStorage.getItem(INDICES_KEY);
    if (stored) {
      return JSON.parse(stored);
    } else {
      localStorage.setItem(INDICES_KEY, JSON.stringify(DEFAULT_INDICES));
      return DEFAULT_INDICES;
    }
  } catch (e) {
    console.error("Error parsing tracked indices", e);
    return DEFAULT_INDICES;
  }
};

export const addTrackedIndex = (indexName: string) => {
  const indices = getTrackedIndices();
  if (!indices.includes(indexName)) {
    const newIndices = [...indices, indexName].sort();
    localStorage.setItem(INDICES_KEY, JSON.stringify(newIndices));
    window.dispatchEvent(new Event(EVENT_KEY));
  }
};

export const removeTrackedIndex = (indexName: string) => {
  const indices = getTrackedIndices();
  const newIndices = indices.filter(i => i !== indexName);
  localStorage.setItem(INDICES_KEY, JSON.stringify(newIndices));
  window.dispatchEvent(new Event(EVENT_KEY));
};

// Helper to generate the specific config for a stock
export const generateInsightConfig = (symbol: string, pk: string, slug: string): InsightsConfig[] => {
  return INSIGHTS_TEMPLATE.map(t => {
    let finalUrl = t.url
      .replace(/stockpk/g, pk)
      .replace(/symbol/g, symbol)
      .replace(/stockslugname/g, slug);

    return {
      ...t,
      url: finalUrl,
    };
  });
};

import React, { useState } from 'react';
import Layout from './components/Layout';
import FundView from './components/FundView';
import StockDashboard from './components/StockDashboard';
import StockSearch from './components/StockSearch';
import TrackingDashboard from './components/TrackingDashboard/TrackingDashboard';
import ConfigurationView from './components/Configuration/ConfigurationView';
import { FundSnapshot, FundSearchResult } from './types';
import { InsightResultItem, IntelligentState, MarketIndexData, SectoralData } from './types/trackingTypes';
import { useInsightExtraction } from './hooks/useInsightExtraction';
import { getTrackedIndices } from './services/trackingStorage';

function App() {
  const [activeTab, setActiveTab] = useState<string>('DASHBOARD');
  const [funds, setFunds] = useState<FundSnapshot[]>();
  const [selectedStock, setSelectedStock] = useState<{symbol: string, name: string} | null>(null);
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(null);

  // --- Lifted State for Persistent Market Data ---
  const [marketIndices, setMarketIndices] = useState<MarketIndexData[]>([]);
  const [moversData, setMoversData] = useState<any[]>([]);
  const [sectoralData, setSectoralData] = useState<SectoralData | null>(null);

  // --- Lifted State for Bulk Insights (Deep Dive) ---
  const deepDiveExtraction = useInsightExtraction();

  // --- Lifted State for Intelligent Tracking ---
  const intelligentExtraction = useInsightExtraction();
  const [intelligentState, setIntelligentState] = useState<IntelligentState>({
      selectedIndex: getTrackedIndices()[0] || "NIFTY 50",
      symbols: [],
      filter: "All",
      page: 1,
      pageSize: 50
  });

  // Handle Navigation
  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (tab !== 'STOCK_DETAIL') {
      setSelectedStock(null);
    }
  };

  const handleFundDataAdded = (newData: FundSnapshot) => {
    setFunds(prev => {
       if (prev && prev.find(f => f.id === newData.id)) return prev;
       return prev ? [...prev, newData] : [newData];
    });
  };

  const handleSelectStock = (symbol: string, name: string) => {
    setSelectedStock({ symbol, name });
    setActiveTab('STOCK_DETAIL');
  };

  const handleSelectFundFromDashboard = (fund: FundSearchResult) => {
    setSelectedFund(fund);
    setActiveTab('FUND_DETAIL');
  };

  const renderContent = () => {
    if (activeTab === 'STOCK_DETAIL' && selectedStock) {
      return (
        <StockDashboard 
          symbol={selectedStock.symbol} 
          stockName={selectedStock.name}
          onBack={() => handleTabChange('STOCK_SEARCH')}
          onSelectFund={handleSelectFundFromDashboard}
        />
      );
    }

    switch (activeTab) {
      case 'DASHBOARD':
        return (
          <TrackingDashboard 
            onSelectStock={handleSelectStock}
            onSelectFund={handleSelectFundFromDashboard}
            // Pass lifted Market Data state
            marketIndices={marketIndices}
            setMarketIndices={setMarketIndices}
            moversData={moversData}
            setMoversData={setMoversData}
            sectoralData={sectoralData}
            setSectoralData={setSectoralData}
            // Pass lifted state for Deep Dive
            deepDiveExtraction={deepDiveExtraction}
            // Pass lifted state for Intelligent Tracking
            intelligentExtraction={intelligentExtraction}
            intelligentState={intelligentState}
            setIntelligentState={setIntelligentState}
          />
        );
      case 'FUND_DETAIL':
        return (
          <FundView 
            funds={funds || []} 
            onFundDataAdded={handleFundDataAdded} 
            onSelectStock={handleSelectStock}
            initialSelectedFund={selectedFund}
          />
        );
      case 'STOCK_SEARCH':
        return (
          <StockSearch onSelectStock={handleSelectStock} />
        );
      case 'CONFIGURATION':
        return (
          <ConfigurationView 
             onSelectStock={handleSelectStock}
             onSelectFund={handleSelectFundFromDashboard}
          />
        );
      default:
        return (
          <TrackingDashboard 
            onSelectStock={handleSelectStock}
            onSelectFund={handleSelectFundFromDashboard}
            marketIndices={marketIndices}
            setMarketIndices={setMarketIndices}
            moversData={moversData}
            setMoversData={setMoversData}
            sectoralData={sectoralData}
            setSectoralData={setSectoralData}
            deepDiveExtraction={deepDiveExtraction}
            intelligentExtraction={intelligentExtraction}
            intelligentState={intelligentState}
            setIntelligentState={setIntelligentState}
          />
        );
    }
  };

  return (
    <Layout activeTab={activeTab === 'STOCK_DETAIL' ? 'STOCK_SEARCH' : activeTab} onTabChange={handleTabChange}>
      {renderContent()}
    </Layout>
  );
}

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Search, Loader2, RefreshCw, Database, Sparkles, ExternalLink, BarChart2, BrainCircuit, X, Globe, TrendingUp, TrendingDown } from 'lucide-react';
import InsightCard from './InsightCard';
import BulkInsightManager from './BulkInsightManager';
import IntelligentTrackingManager from './IntelligentTrackingManager';
import InsightChatbot from './InsightChatbot';
import MarketOverview from './MarketOverview';
import { getTrackedItems, TrackedItem, getTrackedIndices } from '../../services/trackingStorage';
import { fetchMarketInsights } from '../../services/geminiService';
import { fetchMarketIndices } from '../../services/dataService';
import { Insight, InsightResultItem, IntelligentState, MarketIndexData, SectoralData } from '../../types/trackingTypes';
import { FundSearchResult } from '../../types';
import { HEADER_INDICES } from '../../types/constants';
import { useInsightExtraction } from '../../hooks/useInsightExtraction';

interface TrackingDashboardProps {
  onSelectStock: (symbol: string, name: string) => void;
  onSelectFund: (fund: FundSearchResult) => void;

  // Market Data (Lifted)
  marketIndices: MarketIndexData[];
  setMarketIndices: React.Dispatch<React.SetStateAction<MarketIndexData[]>>;
  moversData: any[];
  setMoversData: React.Dispatch<React.SetStateAction<any[]>>;
  sectoralData: SectoralData | null;
  setSectoralData: React.Dispatch<React.SetStateAction<SectoralData | null>>;

  // Deep Dive State
  deepDiveExtraction: ReturnType<typeof useInsightExtraction>;

  // Intelligent State
  intelligentExtraction: ReturnType<typeof useInsightExtraction>;
  intelligentState: IntelligentState;
  setIntelligentState: React.Dispatch<React.SetStateAction<IntelligentState>>;
}

const TrackingDashboard: React.FC<TrackingDashboardProps> = ({ 
  onSelectStock, 
  onSelectFund,
  marketIndices,
  setMarketIndices,
  moversData,
  setMoversData,
  sectoralData,
  setSectoralData,
  deepDiveExtraction,
  intelligentExtraction,
  intelligentState,
  setIntelligentState
}) => {
  const [activeStreamTab, setActiveStreamTab] = useState<'DEEP_DIVE' | 'AI' | 'INTELLIGENT' | 'MARKET'>('MARKET');

  // Global Data State
  const [entities, setEntities] = useState<TrackedItem[]>([]);
  const [trackedIndices, setTrackedIndices] = useState<string[]>([]);

  const [loadingIndices, setLoadingIndices] = useState(false);

  // Market News State
  const [insights, setInsights] = useState<Insight[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Chat State
  const [chatContext, setChatContext] = useState<any[] | null>(null);

  // Local stats for display
  const [intelligentStats, setIntelligentStats] = useState<{ filtered: number; total: number; ignoredList: string[] }>({ filtered: 0, total: 0, ignoredList: [] });
  const [showIgnoredPopover, setShowIgnoredPopover] = useState(false);
  const ignoredPopoverRef = useRef<HTMLDivElement>(null);

  const loadIndices = async () => {
      setLoadingIndices(true);
      const data = await fetchMarketIndices();
      setMarketIndices(data);
      setLoadingIndices(false);
  };

  // Load initial data and listen for updates
  useEffect(() => {
    const loadItems = () => {
        setEntities(getTrackedItems());
        setTrackedIndices(getTrackedIndices());
    };

    loadItems();

    const handleStorageUpdate = () => {
        loadItems();
    };

    window.addEventListener('fundflow_tracking_update', handleStorageUpdate);
    return () => window.removeEventListener('fundflow_tracking_update', handleStorageUpdate);
  }, []); 

  // Fetch Market Indices only if empty
  useEffect(() => {
      if (marketIndices.length === 0) {
          loadIndices();
      }
  }, []);

  // Close popover on click outside
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (ignoredPopoverRef.current && !ignoredPopoverRef.current.contains(event.target as Node)) {
              setShowIgnoredPopover(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const fetchInsights = async () => {
     if (entities.length === 0) return;
     setLoadingInsights(true);
     try {
         const data = await fetchMarketInsights(entities);
         setInsights(data);
     } catch (err) {
         console.error(err);
     } finally {
         setLoadingInsights(false);
     }
  };

  const filteredInsights = useMemo(() => {
    let filtered = insights;
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        filtered = filtered.filter(i => 
        i.title.toLowerCase().includes(lowerQ) || 
        i.content.toLowerCase().includes(lowerQ)
        );
    }
    return filtered.map(item => {
        const entity = entities.find(e => e.id === item.entityId);
        return { ...item, entityName: entity?.name || 'Unknown', entitySymbol: entity?.symbol };
    }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [insights, entities, searchQuery]);

  // Header Indices Data
  const headerIndicesData = useMemo(() => {
      return marketIndices.filter(idx => HEADER_INDICES.includes(idx.index));
  }, [marketIndices]);

  return (
    <div className="flex flex-col gap-6 animate-fade-in w-full max-w-7xl mx-auto relative">

      {/* Header & Tabs */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
         <div className="flex flex-col lg:flex-row justify-between items-start gap-6 mb-6">
            <div className="flex-1">
              <h2 className="text-2xl font-bold text-gray-900">Market Intelligence</h2>
              <p className="text-gray-500 text-sm relative mt-1">
                {activeStreamTab === 'INTELLIGENT' 
                  ? (
                    <span>
                      Showing <strong>{intelligentStats.filtered}</strong> potential stocks from index ({intelligentStats.total} active)
                      {intelligentStats.ignoredList.length > 0 && (
                          <span className="ml-1 text-red-400">
                              • <span 
                                  className="cursor-pointer underline decoration-dotted hover:text-red-600"
                                  onClick={() => setShowIgnoredPopover(!showIgnoredPopover)}
                                >
                                  {intelligentStats.ignoredList.length} ignored
                                </span>
                          </span>
                      )}
                    </span>
                  )
                  : activeStreamTab === 'MARKET' ? "Overview of global and tracked indices"
                  : `Tracking ${entities.length} items in your portfolio`
                }
              </p>

              {/* Ignored List Popover */}
              {showIgnoredPopover && intelligentStats.ignoredList.length > 0 && (
                  <div 
                    ref={ignoredPopoverRef}
                    className="absolute z-50 mt-2 bg-white border border-gray-200 rounded-lg shadow-xl p-3 w-64 animate-fade-in left-0 md:left-auto"
                  >
                      <div className="flex justify-between items-center mb-2 pb-2 border-b border-gray-100">
                          <h4 className="text-xs font-bold text-gray-700">Ignored in this Index</h4>
                          <button onClick={() => setShowIgnoredPopover(false)} className="text-gray-400 hover:text-gray-600">
                              <X size={14} />
                          </button>
                      </div>
                      <div className="max-h-48 overflow-y-auto space-y-1">
                          {intelligentStats.ignoredList.map(sym => (
                              <div 
                                key={sym} 
                                className="text-xs text-gray-600 px-2 py-1 rounded hover:bg-gray-50 cursor-pointer flex justify-between"
                                onClick={() => { onSelectStock(sym, sym); setShowIgnoredPopover(false); }}
                              >
                                  <span>{sym}</span>
                                  <ExternalLink size={10} className="text-gray-400 opacity-50" />
                              </div>
                          ))}
                      </div>
                  </div>
              )}
            </div>

            {/* Subtle Market Header Stats - Vertical Stack */}
            <div className="flex flex-col gap-2 items-end min-w-[200px]">
                <div className="flex items-center gap-2 mb-1">
                     <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">Live Indices</span>
                     <button 
                         onClick={loadIndices}
                         disabled={loadingIndices}
                         className="p-1 text-gray-400 hover:text-indigo-600 transition-colors"
                         title="Refresh Indices"
                     >
                         <RefreshCw size={12} className={loadingIndices ? 'animate-spin' : ''} />
                     </button>
                </div>
                {headerIndicesData.length > 0 ? (
                    headerIndicesData.map(idx => {
                        const isPos = idx.percentChange >= 0;
                        const tooltipText = `PE: ${idx.pe}\nPrevious Close: ${idx.previousClose}\nOpen: ${idx.open}\nHigh: ${idx.high}\nLow: ${idx.low}\nYear High: ${idx.yearHigh}\nYear Low: ${idx.yearLow}`;

                        return (
                            <div 
                                key={idx.index} 
                                className="flex items-center justify-between gap-3 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-100 text-xs cursor-help hover:bg-gray-100 hover:border-gray-300 transition-colors w-full"
                                title={tooltipText}
                            >
                                <span className="font-semibold text-gray-700">{idx.index}</span>
                                <div className="flex items-center gap-2">
                                    <span className="font-mono text-gray-800">{idx.last.toLocaleString()}</span>
                                    <span className={`font-medium w-12 text-right ${isPos ? 'text-green-600' : 'text-red-600'}`}>
                                        {isPos ? '+' : ''}{idx.percentChange.toFixed(2)}%
                                    </span>
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="text-xs text-gray-400 italic">Loading indices...</div>
                )}
            </div>
         </div>

         {/* Tab Navigation - Updated Order */}
         <div className="flex items-center gap-6 border-b border-gray-200 overflow-x-auto">
             <button
                onClick={() => setActiveStreamTab('MARKET')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'MARKET' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Globe size={18} />
                Market Overview
             </button>
